  const widthScreen = useSelector(selectObserveScreenWidth);

  const obs_cal = useSelector(selectCalendarObs)

  

  const [initialize, setInitialize] = useState(false);

  
  const [view, setView] = useState(false);
  const [viewSection, setViewSection] = useState(false);
  const [viewType, set_viewType] = useState(1);
  
  const [obs, set_obs] = useState(0);

  const calRef = useRef();
  
  useEffect(() => {
    if(!initialize){
      setInitialize(true);
      updViewActive(65);
      /*
      if(getStore('userProfile') && getStore('userProfile').email){
        if(!(getStore("userFs") && getStore("userFs")[(getStore('userProfile').id)])){
          updFsObjByColl("users",getStore('userProfile').id,{
              email: getStore('userProfile').email,
              name: getStore('userProfile').name,
              picture: getStore('userProfile').picture
          });
        }
      }*/

      setTimeout(()=>{
        window.scrollTo(0,0);
      },350);
      setTimeout(()=>setView(true),50);
      setTimeout(()=>setViewSection(true),170);
    }
  });
  





  let userA = getBrowser();    
  let isMobile = userA.os === "Android" || userA.os === "iPhone" || getStore("outerWidth")<550 ;
  
  
  

  let pdate = getStore("date2makeAppId") && getStore("date2makeAppId").split("_");

  let nDt =  pdate  && new Date((pdate[1]*1+1)+'/'+pdate[2]+'/'+pdate[0]);



  let hd =  parseDate(nDt)



  const selectTime =  (v,_in09) => {
    updStore("time2makeAppId", v);
    updStore("hasReservationTime", _in09);
    set_obs(gen12CodeId())
  }


  const close =  (v) => {
    updStore("date2makeAppId",null);
    updStore("openTimeCard",null);
    updStore("time2makeAppId",null);
    updStore("hasReservationTime",null);
    updStore("paymentType",null)
    set_obs(gen12CodeId())
  }


  let aval_shift =  getStore("date2makeAppId") && getStore("AppointmentsDates")[getStore("date2makeAppId")] && getStore("AppointmentsDates")[getStore("date2makeAppId")]["shift"]

  const addAppp =  () => {
    /*
      let d2S = aval_shift;
      d2S[getStore("time2makeAppId")]["reserved"] = getProfileId()
      updFsObj(getStore("date2makeAppId"), "shift", d2S)
    */
    updFsObjByField("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved", getProfileId() );
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift": getStore("time2makeAppId"),status:"confirmed"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
    
  }


  
  const cancelAppp =  () => {
    let d2S = aval_shift;
    d2S[getStore("time2makeAppId")]["reserved"] = null;
    //updFsObj(getStore("date2makeAppId"), "shift", d2S)

    deleteFsObj("appointments/"+getStore("date2makeAppId"),"shift."+getStore("time2makeAppId")+".reserved");
    //updFsObjReservation(getProfileId(),getStore("date2makeAppId"),{"shift":null,status:"canceled"})
    calRef && calRef.current && calRef.current.drawCalendar()
    close();
    window.scrollTo(0,0);
  }
  
